#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-26

set -euo pipefail

# Coverage Context for /ork:expect (#1174)
# Usage: bash coverage-context.sh [file1 file2 ...]
# If no args, reads changed files from git diff --name-only
# Output: coverage summary showing which changed files have/lack tests

# Get changed files
if [[ $# -gt 0 ]]; then
  FILES=("$@")
else
  mapfile -t FILES < <(git diff --name-only 2>/dev/null || true)
fi

if [[ ${#FILES[@]} -eq 0 ]]; then
  echo "No changed files to check."
  exit 0
fi

COVERED=()
UNCOVERED=()

for file in "${FILES[@]}"; do
  [[ -z "$file" ]] && continue

  # Skip non-source files
  echo "$file" | grep -qE '\.(lock|log|map|md|json|yaml|yml)$' && continue
  echo "$file" | grep -qE 'node_modules/|dist/|build/|\.git/' && continue
  # Skip test files themselves
  echo "$file" | grep -qE '\.test\.|\.spec\.|__tests__/' && continue

  # Generate candidate test file paths
  FOUND=false

  # Pattern 1: co-located test (src/foo.ts → src/foo.test.ts)
  for ext in ".test.ts" ".test.tsx" ".spec.ts" ".spec.tsx" ".test.js" ".spec.js"; do
    candidate="${file%.*}${ext}"
    if [[ -f "$candidate" ]]; then
      COVERED+=("$file → $candidate")
      FOUND=true
      break
    fi
  done
  [[ "$FOUND" == "true" ]] && continue

  # Pattern 2: __tests__ directory (src/foo.ts → src/__tests__/foo.test.ts)
  dir=$(dirname "$file")
  base=$(basename "$file")
  for ext in ".test.ts" ".test.tsx" ".spec.ts" ".spec.tsx"; do
    candidate="${dir}/__tests__/${base%.*}${ext}"
    if [[ -f "$candidate" ]]; then
      COVERED+=("$file → $candidate")
      FOUND=true
      break
    fi
  done
  [[ "$FOUND" == "true" ]] && continue

  # Pattern 3: tests/ mirror (src/auth.ts → tests/auth.test.ts)
  for prefix in "tests/" "test/" "tests/unit/" "tests/e2e/"; do
    for ext in ".test.ts" ".test.tsx" ".spec.ts" ".spec.tsx"; do
      candidate="${prefix}${base%.*}${ext}"
      if [[ -f "$candidate" ]]; then
        COVERED+=("$file → $candidate")
        FOUND=true
        break 2
      fi
    done
  done
  [[ "$FOUND" == "true" ]] && continue

  # Pattern 4: Python tests (app/auth.py → tests/test_auth.py)
  if echo "$file" | grep -qE '\.py$'; then
    for prefix in "tests/" "tests/unit/" "tests/integration/"; do
      candidate="${prefix}test_${base}"
      if [[ -f "$candidate" ]]; then
        COVERED+=("$file → $candidate")
        FOUND=true
        break
      fi
    done
    [[ "$FOUND" == "true" ]] && continue
  fi

  # No test found
  UNCOVERED+=("$file")
done

# Output
echo "Test Coverage for Changed Files:"
echo ""

if [[ ${#UNCOVERED[@]} -gt 0 ]]; then
  echo "Files WITHOUT test coverage (${#UNCOVERED[@]}) — PRIORITIZE:"
  for f in "${UNCOVERED[@]}"; do
    echo "  ⚠ $f → no test found"
  done
  echo ""
fi

if [[ ${#COVERED[@]} -gt 0 ]]; then
  echo "Files WITH existing tests (${#COVERED[@]}):"
  for f in "${COVERED[@]}"; do
    echo "  ✓ $f"
  done
  echo ""
fi

TOTAL=$(( ${#COVERED[@]} + ${#UNCOVERED[@]} ))
if [[ $TOTAL -gt 0 ]]; then
  PCT=$(( ${#COVERED[@]} * 100 / TOTAL ))
  echo "Coverage: ${#COVERED[@]}/${TOTAL} (${PCT}%)"
fi
